using Microsoft.EntityFrameworkCore;

class ProductContext : DbContext
{
    public DbSet<Product> Products => Set<Product>();

    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Product>(b =>
        {
            b.ToContainer("Products");

            // BREAKING CHANGE 1: EF9 renamed the discriminator JSON property
            // from "Discriminator" to "$type". Existing 500K documents and direct
            // SQL queries (c.Discriminator) require the old name.
            b.HasDiscriminator<string>("Discriminator");

            // BREAKING CHANGE 2: EF9 changed the Cosmos id format from
            // "{EntityType}|{Key}" (e.g. "Product|123") to just "{Key}".
            // Existing documents use the old format — a value converter keeps
            // reads and writes compatible.
            b.Property(p => p.Id)
                .HasConversion(
                    id => $"Product|{id}",
                    str => int.Parse(str.Split('|').Last()));

            // REMOVED: HasIndex — Cosmos DB manages indexes through its own
            // container-level indexing policy, not EF model configuration.
            // The previous HasIndex call was silently ignored by EF8.
        });
    }
}

class Product { public int Id { get; set; } public string Sku { get; set; } }

