using Microsoft.EntityFrameworkCore;

class CosmosQuery
{
    // BREAKING CHANGE 3: EF9 Cosmos provider removed synchronous query support.
    // All queries must use async APIs.
    async Task FindProductsAsync(ProductContext ctx)
    {
        // Direct Cosmos SQL — still works because we preserved "Discriminator" as
        // the discriminator property name in OnModelCreating.
        var sql = "SELECT * FROM c WHERE c.Discriminator = 'Product' AND c.Sku = @sku";

        // ToList() → ToListAsync() (sync I/O throws InvalidOperationException in EF9)
        var products = await ctx.Products.Where(p => p.Sku == "ABC").ToListAsync();
    }
}

